{
var seed = GetInt(parameters, "seed", context.Seed);
var starDensity = GetFloat(parameters, "starDensity", 0.6f);
var starSize = GetFloat(parameters, "starSize", 0.5f);
var starBrightness = GetFloat(parameters, "starBrightness", 0.7f);
var nebulaDensity = GetFloat(parameters, "nebulaDensity", 0.4f);
var nebulaScale = GetFloat(parameters, "nebulaScale", 2f);
var nebulaColor1 = GetColor(parameters, "nebulaColor1", Color.FromRgb(80, 40, 120));
var nebulaColor2 = GetColor(parameters, "nebulaColor2", Color.FromRgb(20, 60, 140));
var bgColor = GetColor(parameters, "bgColor", Color.FromRgb(5, 5, 15));
var celestialSize = GetFloat(parameters, "celestialSize", 0f);
var celestialType = GetChoice(parameters, "celestialType", "none");
var twinkleStrength = GetFloat(parameters, "twinkleStrength", 0f);
var coloredStars = GetBool(parameters, "coloredStars", true);
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var bgR = bgColor.R / 255f; var bgG = bgColor.G / 255f; var bgB = bgColor.B / 255f;
var n1R = nebulaColor1.R / 255f; var n1G = nebulaColor1.G / 255f; var n1B = nebulaColor1.B / 255f;
var n2R = nebulaColor2.R / 255f; var n2G = nebulaColor2.G / 255f; var n2B = nebulaColor2.B / 255f;

// Generate star candidates using hash-based grid
// Divide the tile into a grid; each cell may or may not have a star
var gridCells = (int)(size * 0.5f); // ~0.5 pixel per cell resolution
gridCells = Math.Clamp(gridCells, 8, 64);
var cellPixelSize = size / (float)gridCells;

// Star data: (x, y, size, brightness, r, g, b)
var starCount = (int)(starDensity * gridCells * gridCells * 0.15f);
starCount = Math.Clamp(starCount, 0, 2000);
var stars = new (float x, float y, float s, float br, float r, float g, float b)[starCount];
var starIdx = 0;

for (var gy = 0; gy < gridCells && starIdx < starCount; gy++)
{
    for (var gx = 0; gx < gridCells && starIdx < starCount; gx++)
    {
        var hash = HashToUnit(gx * 31 + gy * 17, seed, 111);
        if (hash > starDensity) continue;

        // Star position within cell
        var sx = (gx + HashToUnit(gx * 7 + gy * 13, seed + 50, 222)) / gridCells;
        var sy = (gy + HashToUnit(gx * 11 + gy * 5, seed + 100, 333)) / gridCells;

        // Star size (1-4 pixels)
        var ss = 0.5f + HashToUnit(gx * 23 + gy * 19, seed + 150, 444) * 1.5f;
        ss *= starSize;

        // Star brightness
        var sb = 0.5f + HashToUnit(gx * 29 + gy * 37, seed + 200, 555) * 0.5f;
        sb *= starBrightness;

        // Star color
        float sr, sg, sbCol;
        if (coloredStars)
        {
            var colorRoll = HashToUnit(gx * 41 + gy * 43, seed + 250, 666);
            if (colorRoll < 0.1f)      { sr = 0.8f; sg = 0.5f; sbCol = 0.3f; } // Orange
            else if (colorRoll < 0.2f) { sr = 0.6f; sg = 0.5f; sbCol = 0.9f; } // Blue
            else if (colorRoll < 0.3f) { sr = 1.0f; sg = 0.7f; sbCol = 0.4f; } // Yellow
            else if (colorRoll < 0.4f) { sr = 0.9f; sg = 0.6f; sbCol = 0.6f; } // Reddish
            else                       { sr = 1.0f; sg = 1.0f; sbCol = 1.0f; } // White
        }
        else
        {
            sr = 1f; sg = 1f; sbCol = 1f;
        }

        // Twinkle phase
        var twinklePhase = HashToUnit(gx * 53 + gy * 59, seed + 300, 777);

        stars[starIdx++] = (sx, sy, ss, sb, sr, sg, sbCol);
    }
}

// Resize array to actual star count
if (starIdx < starCount)
{
    Array.Resize(ref stars, starIdx);
}

// Add ghost stars near edges for seamless horizontal tiling.
// Stars within threshold of the left or right edge also get a wrapped copy
// so their glow appears on the opposite side when the texture is tiled.
var edgeThreshold = Math.Max(1.5f, starSize * 2f) / size;
var extraStars = new List<(float x, float y, float s, float br, float r, float g, float b)>();
foreach (var star in stars)
{
    if (star.x < edgeThreshold)
        extraStars.Add((star.x + 1f, star.y, star.s, star.br, star.r, star.g, star.b));
    if (star.x > 1f - edgeThreshold)
        extraStars.Add((star.x - 1f, star.y, star.s, star.br, star.r, star.g, star.b));
}
if (extraStars.Count > 0)
{
    var oldLen = stars.Length;
    Array.Resize(ref stars, oldLen + extraStars.Count);
    extraStars.CopyTo(stars, oldLen);
}

// Celestial body position
var celestialX = 0.5f;
var celestialY = 0.5f;
var celestialR = 0f;
var celestialG = 0f;
var celestialB = 0f;

if (celestialSize > 0.01f && celestialType != "none")
{
    celestialX = 0.2f + HashToUnit(seed, 0, 888) * 0.6f;
    celestialY = 0.2f + HashToUnit(seed, 1, 999) * 0.6f;

    (celestialR, celestialG, celestialB) = celestialType switch
    {
        "moon" => (220f / 255f, 210f / 255f, 180f / 255f),
        "planet" => (180f / 255f, 120f / 255f, 80f / 255f),
        "star" => (255f / 255f, 200f / 255f, 100f / 255f),
        _ => (0f, 0f, 0f)
    };
}

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    // --- Background: deep space with subtle gradient ---
    var bgGradient = v * 0.08f;
    var fr = Math.Clamp(bgR + bgGradient, 0f, 1f);
    var fg = Math.Clamp(bgG + bgGradient * 0.7f, 0f, 1f);
    var fb = Math.Clamp(bgB + bgGradient * 1.2f, 0f, 1f);

    // --- Nebula clouds ---
    if (nebulaDensity > 0.001f)
    {
        var nebula = TileableFractalNoise(
            u * nebulaScale, v * nebulaScale,
            Math.Max(1, (int)(size * nebulaScale * 0.3f)),
            3, 0.6f, 2.2f, seed + 400);

        var nebula2 = TileableFractalNoise(
            u * nebulaScale * 1.3f + 20f, v * nebulaScale * 1.3f + 20f,
            Math.Max(1, (int)(size * nebulaScale * 0.3f)),
            2, 0.5f, 2f, seed + 500);

        var nBlend = nebula * nebulaDensity * 0.5f;
        var nBlend2 = nebula2 * nebulaDensity * 0.3f;

        fr = Lerp(fr, n1R, nBlend);
        fg = Lerp(fg, n1G, nBlend * 0.8f);
        fb = Lerp(fb, n1B, nBlend * 1.2f);

        fr = Lerp(fr, n2R, nBlend2);
        fg = Lerp(fg, n2G, nBlend2 * 0.8f);
        fb = Lerp(fb, n2B, nBlend2 * 1.2f);
    }

    // --- Celestial body ---
    if (celestialSize > 0.01f && celestialType != "none")
    {
        var dx = u - celestialX;
        var dy = v - celestialY;
        if (dx > 0.5f) dx -= 1f; else if (dx < -0.5f) dx += 1f;
        if (dy > 0.5f) dy -= 1f; else if (dy < -0.5f) dy += 1f;
        var dist = MathF.Sqrt(dx * dx + dy * dy);

        if (dist < celestialSize * 0.5f)
        {
            // Body surface
            var bodyT = dist / (celestialSize * 0.5f);

            if (celestialType == "moon")
            {
                // Moon: cratered surface
                var craterNoise = TileableFractalNoise(
                    u * 20f, v * 20f,
                    Math.Max(1, size / 2), 2, 0.5f, 2f, seed + 600);
                var crater = (craterNoise - 0.5f) * 0.1f;
                fr = Math.Clamp(celestialR + crater - bodyT * 0.1f, 0f, 1f);
                fg = Math.Clamp(celestialG + crater * 0.8f - bodyT * 0.1f, 0f, 1f);
                fb = Math.Clamp(celestialB + crater * 0.6f - bodyT * 0.1f, 0f, 1f);
            }
            else if (celestialType == "star")
            {
                // Star: glowing ball
                var glow = 1f - bodyT;
                glow = glow * glow;
                fr = Math.Clamp(celestialR + glow * 0.5f, 0f, 1f);
                fg = Math.Clamp(celestialG + glow * 0.3f, 0f, 1f);
                fb = Math.Clamp(celestialB + glow * 0.1f, 0f, 1f);
            }
            else
            {
                // Planet: banded surface
                var bands = MathF.Sin(u * 10f + v * 3f) * 0.5f + 0.5f;
                var bandVar = (bands - 0.5f) * 0.15f;
                fr = Math.Clamp(celestialR + bandVar - bodyT * 0.1f, 0f, 1f);
                fg = Math.Clamp(celestialG + bandVar * 0.7f - bodyT * 0.1f, 0f, 1f);
                fb = Math.Clamp(celestialB + bandVar * 0.5f - bodyT * 0.1f, 0f, 1f);
            }

            // Atmosphere glow
            var glowWidth = 0.03f;
            var glowEdge = MathF.Abs(bodyT - 0.95f) / glowWidth;
            if (glowEdge < 1f)
            {
                var glowA = 1f - glowEdge;
                fr += glowA * 0.1f;
                fg += glowA * 0.05f;
            }
        }
        else if (dist < celestialSize * 0.5f + 0.05f)
        {
            // Glow around body
            var glowT = (dist - celestialSize * 0.5f) / 0.05f;
            var glow = 1f - glowT;
            glow = glow * glow * 0.3f;
            fr = Math.Clamp(fr + glow * celestialR, 0f, 1f);
            fg = Math.Clamp(fg + glow * celestialG * 0.5f, 0f, 1f);
            fb = Math.Clamp(fb + glow * celestialB * 0.3f, 0f, 1f);
        }
    }

    // --- Stars ---
    foreach (var (sx, sy, ss, sb, sr, sg, sbColVal) in stars)
    {
        var dx = u - sx;
        var dy = v - sy;
        if (dx > 0.5f) dx -= 1f; else if (dx < -0.5f) dx += 1f;
        if (dy > 0.5f) dy -= 1f; else if (dy < -0.5f) dy += 1f;
        var dist = MathF.Sqrt(dx * dx + dy * dy);

        var pixelDist = dist * size;
        var starRadius = MathF.Max(0.5f, ss * 1.5f);

        if (pixelDist <= starRadius)
        {
            // Star core
            var core = 1f - pixelDist / starRadius;
            core = core * core;
            var brightness = core * sb;

            // Twinkle
            if (twinkleStrength > 0f)
            {
                var twinkle = MathF.Sin(u * 50f + v * 30f + sx * 100f + seed) * 0.5f + 0.5f;
                brightness *= 1f - (1f - twinkle) * twinkleStrength * 0.5f;
            }

            // Glow for larger stars
            if (ss > 0.8f && pixelDist > starRadius * 0.5f)
            {
                // Outer glow: softer, wider
                var glowFalloff = 1f - (pixelDist - starRadius * 0.5f) / (starRadius * 0.5f);
                glowFalloff = MathF.Max(0f, glowFalloff);
                glowFalloff = glowFalloff * glowFalloff * 0.3f;
                fr = Math.Clamp(fr + sr * glowFalloff, 0f, 1f);
                fg = Math.Clamp(fg + sg * glowFalloff * 0.8f, 0f, 1f);
                fb = Math.Clamp(fb + sbColVal * glowFalloff * 0.6f, 0f, 1f);
            }

            // Add star light
            fr = Math.Clamp(fr + sr * brightness, 0f, 1f);
            fg = Math.Clamp(fg + sg * brightness, 0f, 1f);
            fb = Math.Clamp(fb + sbColVal * brightness, 0f, 1f);
        }
    }

    if (invert) { fr = 1f - fr; fg = 1f - fg; fb = 1f - fb; }

    buffer.SetPixel(x, y, Math.Clamp(fr, 0f, 1f), Math.Clamp(fg, 0f, 1f), Math.Clamp(fb, 0f, 1f), 1f);
});

return buffer;
}
